const record = $input.item.json;
const attachments = record.fields?.Attachment || record.fields?.['Creative Upload'] || [];
let imageUrl = '';
if (Array.isArray(attachments) && attachments.length > 0) {
  imageUrl = attachments[0].url || attachments[0].thumbnails?.large?.url || '';
}
const topic = record.fields?.Topic || '';
const brief = record.fields?.Brief || '';
const platform = record.fields?.Platform || '';
const contentType = record.fields?.['Content Type'] || '';
return [{ json: { recordId: record.id, imageUrl, topic, brief, platform, contentType } }];

const response = $input.item.json;
const feedback = response?.choices?.[0]?.message?.content || 'No feedback generated.';
const prev = $('Extract Image URL').item.json;
return [{ json: { ...prev, feedback } }];

const dalleResponse = $input.item.json;
const generatedUrl = dalleResponse?.data?.[0]?.url || '';
const prev = $('Parse Feedback').item.json;
return [{ json: { ...prev, generatedUrl } }];
